public static long solve(long[][] points) {
    // Create a hash to store the count of pairs with the same slope
    java.util.HashMap<String, Integer> slopeCounts = new java.util.HashMap<>();

    // Iterate over all pairs of points
    for (int i = 0; i < points.length; i++) {
        for (int j = i + 1; j < points.length; j++) {
            long x1 = points[i][0];
            long y1 = points[i][1];
            long x2 = points[j][0];
            long y2 = points[j][1];

            // Calculate the slope between p1 and p2
            // Handle vertical lines (infinite slope)
            if (x1 == x2) {
                String slope = "inf";
                slopeCounts.put(slope, slopeCounts.getOrDefault(slope, 0) + 1);
            } else {
                double slope = (double) (y2 - y1) / (x2 - x1);
                String slopeKey = String.valueOf(slope);
                slopeCounts.put(slopeKey, slopeCounts.getOrDefault(slopeKey, 0) + 1);
            }
        }
    }

    // Initialize the result counter
    long result = 0;

    // For each slope, calculate the number of trapezoids that can be formed
    for (int count : slopeCounts.values()) {
        // The number of ways to choose 2 pairs of points with this slope is C(count, 2)
        // Each such pair of pairs forms a trapezoid
        result += (long) (count * (count - 1) / 2);
    }

    return result;
}
